sql:
SELECT name, assembly_level
FROM genome_assemblies
WHERE assembly_level = 'Scaffold';

SELECT COUNT(*) AS public_prokka_annotated_assemblies
FROM genome_assemblies
WHERE is_public = 1 AND annotation_method = 'Prokka';

SELECT name
FROM genome_assemblies
WHERE assembly_id = 0;

SELECT COUNT(*) 
FROM assembly_access 
WHERE assembly_id = 0 AND access_type = 'view';

SELECT SUM(file_size) AS total_file_size
FROM assembly_files
WHERE assembly_id = 0;

external_knowledge:
; Genome assemblies are collections of genomic data for specific organisms; 
; "Accessed more than once" implies frequent usage or interest in the assemblies; 
; The term "most popular" refers to the assemblies with the highest number of accesses; 
; "Data-intensive" refers to the assemblies with the largest total file size.

- File size is measured in megabytes (MB); 
- A major release represents a significant update, often containing substantial improvements or additions; 
- The term 'weigh more' is used metaphorically to describe large file sizes.
